//  STORAGE HELPERS
// SHARED STORAGE (published posts visible to all users) 
// Published posts use window.storage shared=true (cross-user).
// Drafts, auth, and reading history stay in localStorage (private).

const SHARED_POSTS_KEY = "yw:published_posts";
const LOCAL_DRAFTS_KEY = "yw:drafts";

const SharedDB = {
  // Detect whether the artifact storage API is available
  _hasStorage() {
    return typeof window !== "undefined" && typeof window.storage?.get === "function";
  },

  // Fetch all published posts
  async getPublished() {
    if (this._hasStorage()) {
      try {
        const r = await window.storage.get(SHARED_POSTS_KEY, true);
        return r ? JSON.parse(r.value) : [];
      } catch { /* fall through */ }
    }
    // Fallback: localStorage
    try {
      return JSON.parse(localStorage.getItem(SHARED_POSTS_KEY) || "[]");
    } catch { return []; }
  },

  // Save the full published posts array
  async savePublished(posts) {
    const json = JSON.stringify(posts);
    if (this._hasStorage()) {
      try { await window.storage.set(SHARED_POSTS_KEY, json, true); return; } catch { /* fall through */ }
    }
    // Fallback: localStorage
    try { localStorage.setItem(SHARED_POSTS_KEY, json); } catch {}
  },

  // Add or update a single published post
  async upsertPublished(post) {
    const posts = await SharedDB.getPublished();
    const idx = posts.findIndex(p => p.id === post.id);
    if (idx > -1) posts[idx] = post; else posts.unshift(post);
    await SharedDB.savePublished(posts);
  },

  // Remove a published post
  async deletePublished(id) {
    const posts = await SharedDB.getPublished();
    await SharedDB.savePublished(posts.filter(p => p.id !== id));
  },
};

const DB = {
  // Drafts — private, localStorage only
  getDrafts: () => JSON.parse(localStorage.getItem(LOCAL_DRAFTS_KEY) || "[]"),
  saveDrafts: (d) => localStorage.setItem(LOCAL_DRAFTS_KEY, JSON.stringify(d)),
  // Reading history — private
  getHistory: () => JSON.parse(localStorage.getItem("pf_history") || "[]"),
  saveHistory: (h) => localStorage.setItem("pf_history", JSON.stringify(h)),
  // ── Auth helpers (private) 
  getUsers: () => JSON.parse(localStorage.getItem("pf_users") || "[]"),
  saveUsers: (u) => localStorage.setItem("pf_users", JSON.stringify(u)),
  getSession: () => JSON.parse(localStorage.getItem("pf_session") || "null"),
  saveSession: (s) => localStorage.setItem("pf_session", JSON.stringify(s)),
  clearSession: () => localStorage.removeItem("pf_session"),
  getUser: () => {
    const s = JSON.parse(localStorage.getItem("pf_session") || "null");
    return s || { name: "Anonymous", email: "" };
  },
};

//  Simple password hash (FNV-1a, good enough for local demo)
function hashPassword(pw) {
  let h = 2166136261;
  for (let i = 0; i < pw.length; i++) {
    h ^= pw.charCodeAt(i);
    h = Math.imul(h, 16777619) >>> 0;
  }
  return h.toString(16);
}

function uid() {
  return Math.random().toString(36).slice(2) + Date.now().toString(36);
}

function timeAgo(iso) {
  const d = new Date(iso),
    diff = (Date.now() - d) / 1000;
  if (diff < 60) return "just now";
  if (diff < 3600) return Math.floor(diff / 60) + "m ago";
  if (diff < 86400) return Math.floor(diff / 3600) + "h ago";
  if (diff < 604800) return Math.floor(diff / 86400) + "d ago";
  return d.toLocaleDateString("en", {
    month: "short",
    day: "numeric",
    year: "numeric",
  });
}

function readTime(md) {
  // Strip markdown syntax before counting words
  const plain = (md || "")
    .replace(/```[\s\S]*?```/g, "")   // fenced code blocks
    .replace(/`[^`]+`/g, "")            // inline code
    .replace(/!?\[[^\]]*\]\([^)]*\)/g, "") // links/images
    .replace(/^#{1,6}\s+/gm, "")       // headings
    .replace(/[*_~>#`|\-]/g, "")       // inline markers
    .replace(/<[^>]*>/g, "");           // any leftover HTML
  const words = plain.trim().split(/\s+/).filter(Boolean).length;
  return Math.max(1, Math.round(words / 200));
}

