//  GLOBAL STYLES (inject into <head>) 
const STYLES = `
  @import url('https://fonts.googleapis.com/css2?family=Lora:wght@400;600;700&family=DM+Sans:wght@400;500;600&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --bg: #1c1b18;
    --surface: #26241f;
    --border: #3a3730;
    --text: #ede8df;
    --muted: #8a8478;
    --accent: #6b9fd4;
    --accent-light: #1e2e42;
    --tag-bg: #2e2c27;
    --tag-text: #c4bfb4;
    --danger: #e05c4b;
    --radius: 10px;
    --shadow: 0 1px 4px rgba(0,0,0,0.35);
  }

  html, body, #root {
    margin: 0;
    padding: 0;
    width: 100%;
    min-height: 100vh;
    background: var(--bg);
  }

  body {
    font-family: 'DM Sans', sans-serif;
    background: var(--bg);
    color: var(--text);
    min-height: 100vh;
    font-size: 15px;
  }

  h1, h2, h3 { font-family: 'Lora', serif; }
  a { text-decoration: none; color: inherit; }
  button { cursor: pointer; font-family: 'DM Sans', sans-serif; }
  input, textarea { font-family: 'DM Sans', sans-serif; }

  .btn {
    display: inline-flex; align-items: center; gap: 6px;
    padding: 8px 16px; border-radius: 8px; font-size: 14px; font-weight: 500;
    border: 1px solid var(--border); background: var(--surface); color: var(--text);
    transition: all .15s;
  }
  .btn:hover { background: var(--tag-bg); }
  .btn-primary { background: var(--accent); color: #fff; border-color: var(--accent); }
  .btn-primary:hover { background: #1e3a5f; border-color: #1e3a5f; }
  .btn-ghost { border-color: transparent; background: transparent; }
  .btn-ghost:hover { background: var(--tag-bg); }
  .btn-danger { border-color: transparent; background: transparent; color: var(--danger); }
  .btn-danger:hover { background: #fdecea; }

  .card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    box-shadow: var(--shadow);
  }

  .badge { display: inline-block; font-size: 11px; font-weight: 500; padding: 2px 8px; border-radius: 20px; background: var(--tag-bg); color: var(--tag-text); }
  .badge-published { background: #e6f4ea; color: #2d6a4f; }
  .badge-draft { background: #fef9e7; color: #7d6608; }

  input[type=text], input[type=url], textarea {
    width: 100%; padding: 9px 12px; border: 1px solid var(--border);
    border-radius: 8px; background: var(--surface); color: var(--text);
    font-size: 14px; outline: none; transition: border .15s;
  }
  input[type=text]:focus, input[type=url]:focus, input[type=password]:focus, textarea:focus { border-color: var(--accent); }
  textarea { resize: vertical; min-height: 320px; line-height: 1.7; }

  label { font-size: 13px; font-weight: 500; color: var(--muted); display: block; margin-bottom: 4px; }
  .field { margin-bottom: 18px; }

  .tag {
    display: inline-block; font-size: 11px; padding: 3px 10px;
    border-radius: 20px; background: var(--tag-bg); color: var(--tag-text); font-weight: 500;
  }

  .post-content h1, .post-content h2, .post-content h3 { font-family: 'Lora', serif; margin: 1.5em 0 .5em; line-height: 1.3; }
  .post-content p { margin-bottom: 1em; line-height: 1.8; }
  .post-content ul, .post-content ol { margin: 1em 0 1em 1.5em; }
  .post-content li { margin-bottom: .4em; }
  .post-content blockquote { border-left: 3px solid var(--accent); padding-left: 16px; color: var(--muted); margin: 1em 0; font-style: italic; }
  .post-content code { background: var(--tag-bg); padding: 2px 6px; border-radius: 4px; font-size: 13px; }
  .post-content pre { background: var(--tag-bg); padding: 16px; border-radius: 8px; overflow: auto; margin: 1em 0; }
  .post-content a { color: var(--accent); text-decoration: underline; }

  .modal-overlay { position: fixed; inset: 0; background: rgba(0,0,0,.65); display: flex; align-items: center; justify-content: center; z-index: 200; }
  .modal { background: var(--surface); border-radius: 12px; padding: 28px; max-width: 400px; width: 90%; box-shadow: 0 8px 32px rgba(0,0,0,.15); }
  .modal h3 { font-size: 17px; margin-bottom: 8px; }
  .modal p { font-size: 14px; color: var(--muted); margin-bottom: 24px; }
  .modal-actions { display: flex; gap: 10px; justify-content: flex-end; }

  .toolbar { display: flex; flex-wrap: wrap; gap: 4px; padding: 8px; border-bottom: 1px solid var(--border); background: var(--bg); }
  .toolbar button { padding: 4px 8px; border: 1px solid var(--border); border-radius: 6px; background: var(--surface); font-size: 13px; cursor: pointer; }
  .toolbar button:hover { background: var(--tag-bg); }

  .editor-area {
    width: 100%; min-height: 300px; padding: 16px; border: none;
    font-family: 'DM Sans', sans-serif; font-size: 15px; line-height: 1.8;
    resize: vertical; outline: none; color: var(--text); background: var(--surface);
  }
  .editor-area:empty::before { content: attr(data-placeholder); color: var(--muted); pointer-events: none; }

  .spinner {
    width: 20px; height: 20px; border: 2px solid var(--border);
    border-top-color: var(--accent); border-radius: 50%;
    animation: spin .7s linear infinite; margin: 60px auto; display: block;
  }
  @keyframes spin { to { transform: rotate(360deg); } }

  .empty { text-align: center; padding: 60px 20px; color: var(--muted); }

  input[type=password] { letter-spacing: .05em; width: 100%; padding: 9px 12px; border: 1px solid var(--border); border-radius: 8px; background: var(--surface); color: var(--text); font-size: 14px; outline: none; transition: border .15s; }
  input[type=text]::placeholder, input[type=password]::placeholder { letter-spacing: normal; }

  /*  TAG FILTER BAR */
  .tag-bar {
    display: flex; align-items: center; gap: 8px; flex-wrap: wrap;
    margin-bottom: 24px;
  }
  .tag-filter {
    display: inline-flex; align-items: center; gap: 5px;
    padding: 5px 12px; border-radius: 20px; font-size: 12px; font-weight: 500;
    border: 1.5px solid var(--border); background: var(--surface); color: var(--muted);
    cursor: pointer; transition: all .15s; white-space: nowrap; line-height: 1;
    font-family: 'DM Sans', sans-serif;
  }
  .tag-filter:hover { border-color: var(--accent); color: var(--accent); background: var(--accent-light); }
  .tag-filter.active {
    background: var(--accent); color: #fff; border-color: var(--accent);
  }
  .tag-filter .tag-count {
    background: rgba(255,255,255,.25); color: inherit;
    padding: 1px 6px; border-radius: 10px; font-size: 10px;
  }
  .tag-filter:not(.active) .tag-count {
    background: var(--tag-bg); color: var(--muted);
  }
  /* Clickable tag chip on PostCard */
  .tag-chip {
    display: inline-block; font-size: 11px; padding: 3px 10px;
    border-radius: 20px; background: var(--tag-bg); color: var(--tag-text);
    font-weight: 500; cursor: pointer; transition: background .12s, color .12s;
  }
  .tag-chip:hover { background: var(--accent); color: #fff; }

  /*  IMAGE UPLOADER  */
  .img-drop-zone {
    border: 2px dashed var(--border); border-radius: 10px;
    background: var(--bg); cursor: pointer;
    transition: border-color .2s, background .2s;
    position: relative; overflow: hidden;
  }
  .img-drop-zone:hover, .img-drop-zone.drag-over {
    border-color: var(--accent); background: var(--accent-light);
  }
  .img-drop-zone input[type=file] {
    position: absolute; inset: 0; opacity: 0; cursor: pointer; width: 100%; height: 100%;
  }
  .img-preview-wrap {
    position: relative; border-radius: 10px; overflow: hidden;
    border: 1px solid var(--border);
  }
  .img-preview-wrap img { display: block; width: 100%; height: 220px; object-fit: cover; }
  .img-preview-actions {
    position: absolute; top: 10px; right: 10px; display: flex; gap: 6px;
  }
  .img-preview-btn {
    padding: 5px 10px; border-radius: 6px; font-size: 12px; font-weight: 500;
    border: none; cursor: pointer; backdrop-filter: blur(6px); transition: opacity .15s;
  }
  .img-preview-btn:hover { opacity: .85; }
  .img-upload-progress {
    position: absolute; inset: 0; background: rgba(28,27,24,.75);
    display: flex; align-items: center; justify-content: center; flex-direction: column; gap: 8px;
  }

  /* ── MARKDOWN EDITOR ── */
  .md-editor-wrap {
    border: 1px solid var(--border); border-radius: 8px; overflow: hidden;
    background: var(--surface); display: flex; flex-direction: column;
  }
  .md-toolbar {
    display: flex; align-items: center; gap: 2px; padding: 6px 8px;
    border-bottom: 1px solid var(--border); background: var(--bg);
    flex-wrap: wrap;
  }
  .md-toolbar button {
    padding: 4px 8px; border: 1px solid transparent; border-radius: 5px;
    background: none; font-size: 12px; cursor: pointer; color: var(--muted);
    font-family: 'DM Sans', sans-serif; font-weight: 500; line-height: 1.4;
    transition: all .1s;
  }
  .md-toolbar button:hover { background: var(--border); color: var(--text); }
  .md-toolbar .sep { width: 1px; height: 16px; background: var(--border); margin: 0 4px; }
  .md-tabs {
    display: flex; border-bottom: 1px solid var(--border); background: var(--bg);
  }
  .md-tab {
    padding: 8px 16px; font-size: 13px; font-weight: 500; cursor: pointer;
    border: none; background: none; color: var(--muted); transition: all .15s;
    border-bottom: 2px solid transparent; margin-bottom: -1px;
    font-family: 'DM Sans', sans-serif;
  }
  .md-tab.active { color: var(--accent); border-bottom-color: var(--accent); background: var(--surface); }
  /* Desktop: hide the tab bar, always show split pane */
  @media (min-width: 641px) { .md-tabs { display: none !important; } .md-pane-hide { display: flex !important; } }
  .md-panes { display: flex; min-height: 360px; }
  .md-textarea {
    flex: 1; padding: 16px; border: none; outline: none; resize: none;
    font-family: 'DM Mono', 'Fira Mono', 'Courier New', monospace; font-size: 14px;
    line-height: 1.75; color: var(--text); background: var(--surface);
    min-height: 360px; tab-size: 2;
  }
  .md-divider { width: 1px; background: var(--border); flex-shrink: 0; }
  .md-preview {
    flex: 1; padding: 16px 20px; overflow-y: auto; min-height: 360px;
    font-size: 15px; line-height: 1.8; color: var(--text);
  }
  .md-preview-empty { color: var(--muted); font-size: 14px; font-style: italic; }
  .md-preview h1 { font-family: 'Lora',serif; font-size: 1.7em; margin: 1.2em 0 .4em; line-height: 1.3; }
  .md-preview h2 { font-family: 'Lora',serif; font-size: 1.35em; margin: 1.1em 0 .4em; line-height: 1.3; }
  .md-preview h3 { font-family: 'Lora',serif; font-size: 1.1em; margin: 1em 0 .3em; }
  .md-preview p { margin-bottom: .9em; }
  .md-preview ul, .md-preview ol { margin: .5em 0 .9em 1.5em; }
  .md-preview li { margin-bottom: .25em; }
  .md-preview blockquote { border-left: 3px solid var(--accent); padding: 4px 0 4px 14px; color: var(--muted); margin: 1em 0; font-style: italic; }
  .md-preview code { background: var(--tag-bg); padding: 1px 5px; border-radius: 4px; font-family: monospace; font-size: .88em; }
  .md-preview pre { background: var(--tag-bg); padding: 14px; border-radius: 8px; overflow-x: auto; margin: 1em 0; }
  .md-preview pre code { background: none; padding: 0; font-size: .87em; }
  .md-preview a { color: var(--accent); text-decoration: underline; }
  .md-preview hr { border: none; border-top: 1px solid var(--border); margin: 1.5em 0; }
  .md-preview strong { font-weight: 600; }
  .md-preview em { font-style: italic; }
  .md-preview table { width: 100%; border-collapse: collapse; margin: 1em 0; font-size: 14px; }
  .md-preview th { background: var(--tag-bg); font-weight: 600; text-align: left; }
  .md-preview th, .md-preview td { padding: 7px 12px; border: 1px solid var(--border); }
  .md-preview img { max-width: 100%; border-radius: 6px; margin: .5em 0; }
  /* Mobile: single-pane with tabs */
  @media (max-width: 640px) {
    .md-panes { flex-direction: column; }
    .md-divider { display: none; }
    .md-pane-hide { display: none !important; }
    .md-textarea { min-height: 280px; border-left: none; }
    .md-preview { border-left: none !important; min-height: 280px; }
  }

  /* RESPONSIVE */
  .hide-mobile { display: flex; }
  .show-mobile { display: none; }

  /* Bottom nav bar (mobile) */
  .bottom-nav {
    display: none;
    position: fixed; bottom: 0; left: 0; right: 0; z-index: 100;
    background: rgba(28,27,24,.96); backdrop-filter: blur(12px);
    border-top: 1px solid var(--border);
    padding: 6px 0 max(6px, env(safe-area-inset-bottom));
  }
  .bottom-nav-item {
    flex: 1; display: flex; flex-direction: column; align-items: center;
    gap: 3px; padding: 4px 0; background: none; border: none; cursor: pointer;
    color: var(--muted); font-size: 10px; font-family: 'DM Sans', sans-serif; font-weight: 500;
    transition: color .15s;
  }
  .bottom-nav-item.active { color: var(--accent); }

  /* Post grid: 2 cols on tablet, 1 on mobile */
  .post-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 20px;
  }

  /* My-posts row: hide thumbnail on very small screens */
  .post-row-thumb { display: block; }

  /* History card thumbnail */
  .hist-thumb { display: block; }

  /* Write page: full-width action bar on mobile */
  .write-actions { display: flex; gap: 10px; flex-wrap: wrap; }

  /* Auth card padding */
  .auth-card-pad { padding: 36px 32px; }

  @media (max-width: 640px) {
    .hide-mobile { display: none !important; }
    .show-mobile { display: flex !important; }
    .bottom-nav { display: flex; }

    /* Give main content breathing room above bottom nav */
    main { padding-bottom: 80px !important; }

    .post-grid { grid-template-columns: 1fr; gap: 14px; }
    .post-row-thumb { display: none; }
    .hist-thumb { display: none; }

    .write-actions { gap: 8px; }
    .write-actions .btn { flex: 1; justify-content: center; }

    .auth-card-pad { padding: 28px 20px; }

    /* Tighten page headers on mobile */
    .page-header-h1 { font-size: 22px !important; }

    /* Post detail typography */
    .post-detail-title { font-size: 24px !important; }

    /* Reading history search row */
    .hist-header { flex-direction: column; align-items: flex-start !important; }
    .hist-search input { width: 100% !important; }
    .hist-search { width: 100%; }

    /* My-posts action buttons — text labels off, icons only */
    .post-row-label { display: none; }

    /* Confirm modal */
    .modal { padding: 22px 18px; }
  }

  @media (max-width: 400px) {
    .post-grid { gap: 10px; }
    .auth-card-pad { padding: 22px 16px; }
  }
`;

//  INJECT STYLES 
function GlobalStyles() {
  useEffect(() => {
    const el = document.createElement("style");
    el.textContent = STYLES;
    document.head.appendChild(el);
    return () => document.head.removeChild(el);
  }, []);
  return null;
}

// MARKDOWN PARSER (zero dependencies) 
function parseMarkdown(md) {
  if (!md) return "";
  let html = md;

  // Escape HTML entities first (protect user input)
  html = html.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");

  // Fenced code blocks (``` lang ... ```)
  html = html.replace(/```([\w]*)?\n([\s\S]*?)```/gm, (_, lang, code) =>
    `<pre><code${lang ? ` class="language-${lang}"` : ""}>${code.trimEnd()}</code></pre>`
  );

  // Horizontal rules
  html = html.replace(/^[ \t]*[-*_]{3,}[ \t]*$/gm, "<hr>");

  // Headings
  html = html.replace(/^######\s+(.+)$/gm, "<h6>$1</h6>");
  html = html.replace(/^#####\s+(.+)$/gm, "<h5>$1</h5>");
  html = html.replace(/^####\s+(.+)$/gm, "<h4>$1</h4>");
  html = html.replace(/^###\s+(.+)$/gm, "<h3>$1</h3>");
  html = html.replace(/^##\s+(.+)$/gm, "<h2>$1</h2>");
  html = html.replace(/^#\s+(.+)$/gm, "<h1>$1</h1>");

  // Blockquotes (multi-line)
  html = html.replace(/^&gt;\s?(.*)$/gm, "<blockquote>$1</blockquote>");
  // Collapse adjacent blockquotes
  html = html.replace(/<\/blockquote>\n<blockquote>/g, "\n");

  // Tables
  html = html.replace(/((?:^\|.+\|\s*\n)+)/gm, (match) => {
    const rows = match.trim().split("\n").filter(r => !/^\|[-: |]+\|$/.test(r));
    if (rows.length < 1) return match;
    const toTd = (row, tag) =>
      "<tr>" + row.split("|").filter((_, i, a) => i > 0 && i < a.length - 1)
        .map(c => `<${tag}>${c.trim()}</${tag}>`).join("") + "</tr>";
    const [head, ...body] = rows;
    return `<table><thead>${toTd(head, "th")}</thead><tbody>${body.map(r => toTd(r, "td")).join("")}</tbody></table>`;
  });

  // Unordered lists
  html = html.replace(/((?:^[ \t]*[-*+]\s.+\n?)+)/gm, match => {
    const items = match.trim().split("\n").map(l => `<li>${l.replace(/^[ \t]*[-*+]\s/, "")}</li>`).join("");
    return `<ul>${items}</ul>`;
  });

  // Ordered lists
  html = html.replace(/((?:^[ \t]*\d+\.\s.+\n?)+)/gm, match => {
    const items = match.trim().split("\n").map(l => `<li>${l.replace(/^[ \t]*\d+\.\s/, "")}</li>`).join("");
    return `<ol>${items}</ol>`;
  });

  // Inline code (before bold/italic to protect backtick content)
  const codePH = {};
  let cphi = 0;
  html = html.replace(/`([^`]+)`/g, (_, code) => {
    const key = `\x00CODE${cphi++}\x00`;
    codePH[key] = `<code>${code}</code>`;
    return key;
  });

  // Images before links
  html = html.replace(/!\[([^\]]*?)\]\(([^)]+?)\)/g, '<img src="$2" alt="$1">');

  // Links
  html = html.replace(/\[([^\]]+?)\]\(([^)]+?)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>');

  // Bold + italic  ***text***
  html = html.replace(/\*\*\*(.+?)\*\*\*/g, "<strong><em>$1</em></strong>");
  // Bold __text__ or **text**
  html = html.replace(/__(\S[\s\S]*?\S|\S)__/g, "<strong>$1</strong>");
  html = html.replace(/\*\*(\S[\s\S]*?\S|\S)\*\*/g, "<strong>$1</strong>");
  // Italic _text_ or *text*
  html = html.replace(/_(\S[\s\S]*?\S|\S)_/g, "<em>$1</em>");
  html = html.replace(/\*(\S[\s\S]*?\S|\S)\*/g, "<em>$1</em>");
  // Strikethrough
  html = html.replace(/~~(.+?)~~/g, "<del>$1</del>");

  // Restore inline code
  Object.entries(codePH).forEach(([k, v]) => { html = html.split(k).join(v); });

  // Paragraphs — wrap non-block lines
  const blockTags = /^(<h[1-6]|<ul|<ol|<li|<blockquote|<pre|<table|<thead|<tbody|<tr|<th|<td|<hr|<img)/;
  html = html.split("\n\n").map(block => {
    const trimmed = block.trim();
    if (!trimmed) return "";
    if (blockTags.test(trimmed)) return trimmed;
    // Single newlines within a paragraph → line break
    return `<p>${trimmed.replace(/\n/g, "<br>")}</p>`;
  }).join("\n");

  return html;
}

// MARKDOWN EDITOR COMPONENT 
function MarkdownEditor({ value, onChange }) {
  const taRef = useRef();
  // 0=split, 1=edit-only, 2=preview-only. On mobile default to edit tab
  const [mobileTab, setMobileTab] = useState(0); // 0=write, 1=preview

  // Toolbar insert helpers
  function wrap(before, after = before, placeholder = "text") {
    const ta = taRef.current;
    if (!ta) return;
    const start = ta.selectionStart, end = ta.selectionEnd;
    const sel = value.slice(start, end) || placeholder;
    const next = value.slice(0, start) + before + sel + after + value.slice(end);
    onChange(next);
    setTimeout(() => {
      ta.focus();
      const s = start + before.length, e = s + sel.length;
      ta.setSelectionRange(s, e);
    }, 0);
  }

  function insertLine(prefix) {
    const ta = taRef.current;
    if (!ta) return;
    const start = ta.selectionStart;
    const lineStart = value.lastIndexOf("\n", start - 1) + 1;
    const next = value.slice(0, lineStart) + prefix + value.slice(lineStart);
    onChange(next);
    setTimeout(() => { ta.focus(); ta.setSelectionRange(start + prefix.length, start + prefix.length); }, 0);
  }

  // Handle Tab key for indentation
  function handleKeyDown(e) {
    if (e.key === "Tab") {
      e.preventDefault();
      const ta = e.target;
      const s = ta.selectionStart, end = ta.selectionEnd;
      const next = value.slice(0, s) + "  " + value.slice(end);
      onChange(next);
      setTimeout(() => { ta.setSelectionRange(s + 2, s + 2); }, 0);
    }
  }

  const preview = parseMarkdown(value);
  const toolbarButtons = [
    { label: "H1", title: "Heading 1", action: () => insertLine("# ") },
    { label: "H2", title: "Heading 2", action: () => insertLine("## ") },
    { label: "H3", title: "Heading 3", action: () => insertLine("### ") },
    { label: "sep" },
    { label: <strong>B</strong>, title: "Bold", action: () => wrap("**") },
    { label: <em>I</em>, title: "Italic", action: () => wrap("_") },
    { label: <del>S</del>, title: "Strikethrough", action: () => wrap("~~") },
    { label: "sep" },
    { label: "• List", title: "Bullet list", action: () => insertLine("- ") },
    { label: "1. List", title: "Ordered list", action: () => insertLine("1. ") },
    { label: "Quote", title: "Blockquote", action: () => insertLine("> ") },
    { label: "sep" },
    { label: "`Code`", title: "Inline code", action: () => wrap("`") },
    { label: "```Block", title: "Code block", action: () => wrap("```\n", "\n```", "code here") },
    { label: "sep" },
    { label: "Link", title: "Insert link", action: () => { const url = prompt("URL:"); if (url) wrap("[", `](${url})`); } },
    { label: "Image", title: "Insert image", action: () => { const url = prompt("Image URL:"); if (url) { onChange(value + `\n![Image](${url})`); } } },
    { label: "---", title: "Horizontal rule", action: () => onChange(value + "\n\n---\n\n") },
  ];

  return (
    <div className="md-editor-wrap">
      {/* Toolbar */}
      <div className="md-toolbar">
        {toolbarButtons.map((btn, i) =>
          btn.label === "sep"
            ? <div key={i} className="sep" />
            : <button key={i} title={btn.title} onMouseDown={e => { e.preventDefault(); btn.action(); }}>{btn.label}</button>
        )}
      </div>

      {/* Mobile tab switcher — shown via CSS on small screens */}
      <div className="md-tabs">
        <button className={`md-tab${mobileTab === 0 ? " active" : ""}`} onClick={() => setMobileTab(0)}>Write</button>
        <button className={`md-tab${mobileTab === 1 ? " active" : ""}`} onClick={() => setMobileTab(1)}>Preview</button>
      </div>

      {/* Split panes */}
      <div className="md-panes">
        {/* Editor pane — hidden on mobile when preview tab active */}
        <textarea
          ref={taRef}
          className={`md-textarea${mobileTab === 1 ? " md-pane-hide" : ""}`}
          value={value}
          onChange={e => onChange(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Start writing in Markdown…&#10;&#10;# Heading&#10;**bold**, _italic_, `code`&#10;&#10;- bullet list&#10;1. numbered list&#10;&#10;> blockquote"
          spellCheck
        />

        {/* Divider — desktop only */}
        <div className="md-divider" />

        {/* Preview pane — hidden on mobile when editor tab active */}
        <div
          className={`md-preview${mobileTab === 0 ? " md-pane-hide" : ""}`}
          style={{ borderLeft: "1px solid var(--border)" }}
        >
          {value.trim()
            ? <div dangerouslySetInnerHTML={{ __html: preview }} />
            : <p className="md-preview-empty">Preview will appear here as you write…</p>}
        </div>
      </div>

      {/* Character / word count */}
      <div style={{ padding: "5px 12px", borderTop: "1px solid var(--border)", background: "var(--bg)", fontSize: 11, color: "var(--muted)", display: "flex", gap: 16 }}>
        <span>{value.replace(/\s+/g, " ").trim().split(" ").filter(Boolean).length} words</span>
        <span>{value.length} chars</span>
        <span>{Math.max(1, Math.round(value.replace(/[#*`_~>\[\]!|\-]/g, "").split(/\s+/).filter(Boolean).length / 200))} min read</span>
      </div>
    </div>
  );
}

// IMAGE UPLOADER
function ImageUploader({ value, onChange }) {
  const [dragging, setDragging] = useState(false);
  const [processing, setProcessing] = useState(false);
  const [showUrlInput, setShowUrlInput] = useState(false);
  const [urlInput, setUrlInput] = useState("");
  const fileRef = useRef();

  function fileToBase64(file) {
    return new Promise((resolve, reject) => {
      // Validate type
      if (!file.type.startsWith("image/")) { reject(new Error("Please upload an image file.")); return; }
      // Warn on large files (>4 MB)
      if (file.size > 4 * 1024 * 1024) { reject(new Error("Image is too large (max 4 MB). Try compressing it first.")); return; }
      const reader = new FileReader();
      reader.onload = e => resolve(e.target.result); // data:image/...;base64,...
      reader.onerror = () => reject(new Error("Failed to read file."));
      reader.readAsDataURL(file);
    });
  }

  async function handleFiles(files) {
    if (!files || !files.length) return;
    setProcessing(true);
    try {
      const b64 = await fileToBase64(files[0]);
      onChange(b64);
    } catch (e) {
      alert(e.message);
    }
    setProcessing(false);
  }

  function onDrop(e) {
    e.preventDefault();
    setDragging(false);
    handleFiles(e.dataTransfer.files);
  }

  function onPaste(e) {
    const items = Array.from(e.clipboardData?.items || []);
    const imgItem = items.find(i => i.kind === "file" && i.type.startsWith("image/"));
    if (imgItem) { e.preventDefault(); handleFiles([imgItem.getAsFile()]); }
  }

  function applyUrl() {
    const u = urlInput.trim();
    if (u) { onChange(u); setUrlInput(""); }
    setShowUrlInput(false);
  }

  // Paste anywhere on the page when uploader is mounted
  useEffect(() => {
    document.addEventListener("paste", onPaste);
    return () => document.removeEventListener("paste", onPaste);
  }, []);

  // Has image 
  if (value) {
    return (
      <div className="img-preview-wrap">
        <img src={value} alt="Cover" />
        {processing && (
          <div className="img-upload-progress">
            <span className="spinner" style={{ margin: 0 }} />
            <span style={{ fontSize: 13, color: "var(--muted)" }}>Processing…</span>
          </div>
        )}
        <div className="img-preview-actions">
          <button className="img-preview-btn"
            style={{ background: "rgba(38,36,31,.9)", color: "var(--text)" }}
            onClick={() => fileRef.current?.click()}>
            Change
          </button>
          <button className="img-preview-btn"
            style={{ background: "rgba(192,57,43,.9)", color: "#fff" }}
            onClick={() => onChange("")}>
            Remove
          </button>
        </div>
        {/* Hidden file input for "Change" */}
        <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }}
          onChange={e => handleFiles(e.target.files)} />
      </div>
    );
  }

  //  No image — drop zone 
  return (
    <div>
      <div
        className={`img-drop-zone${dragging ? " drag-over" : ""}`}
        onDragOver={e => { e.preventDefault(); setDragging(true); }}
        onDragLeave={() => setDragging(false)}
        onDrop={onDrop}
        style={{ padding: "36px 24px", textAlign: "center" }}
      >
        <input type="file" accept="image/*" onChange={e => handleFiles(e.target.files)} />
        {processing ? (
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 10 }}>
            <span className="spinner" style={{ margin: 0 }} />
            <span style={{ fontSize: 13, color: "var(--muted)" }}>Processing image…</span>
          </div>
        ) : (
          <>
            <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"
              style={{ color: "var(--muted)", margin: "0 auto 10px", display: "block", opacity: .6 }}>
              <rect x="3" y="3" width="18" height="18" rx="2" ry="2"/>
              <circle cx="8.5" cy="8.5" r="1.5"/>
              <polyline points="21 15 16 10 5 21"/>
            </svg>
            <p style={{ fontSize: 14, fontWeight: 500, color: "var(--text)", marginBottom: 4 }}>
              Drop an image here or click to upload
            </p>
            <p style={{ fontSize: 12, color: "var(--muted)" }}>
              PNG, JPG, GIF, WebP · max 4 MB · or paste from clipboard
            </p>
          </>
        )}
      </div>

      {/* URL fallback */}
      <div style={{ marginTop: 8 }}>
        {showUrlInput ? (
          <div style={{ display: "flex", gap: 6 }}>
            <input type="url" value={urlInput} onChange={e => setUrlInput(e.target.value)}
              placeholder="https://images.unsplash.com/…"
              onKeyDown={e => { if (e.key === "Enter") applyUrl(); if (e.key === "Escape") setShowUrlInput(false); }}
              autoFocus />
            <button className="btn" onClick={applyUrl} style={{ whiteSpace: "nowrap" }}>Use URL</button>
            <button className="btn btn-ghost" onClick={() => setShowUrlInput(false)}>✕</button>
          </div>
        ) : (
          <button className="btn btn-ghost" onClick={() => setShowUrlInput(true)}
            style={{ fontSize: 12, padding: "5px 10px", color: "var(--muted)" }}>
            Use image URL instead
          </button>
        )}
      </div>
    </div>
  );
}

//  TOAST 
function Toast({ msg, onDone }) {
  useEffect(() => {
    const t = setTimeout(onDone, 2400);
    return () => clearTimeout(t);
  }, []);
  return (
    <div style={{ position: "fixed", bottom: 24, left: "50%", transform: "translateX(-50%)", background: "var(--text)", color: "#fff", padding: "10px 20px", borderRadius: 8, fontSize: 14, zIndex: 999, whiteSpace: "nowrap", boxShadow: "0 4px 16px rgba(0,0,0,.2)" }}>
      {msg}
    </div>
  );
}

//  CONFIRM MODAL
function Confirm({ title, desc, onConfirm, onCancel }) {
  return (
    <div className="modal-overlay" onClick={onCancel}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <h3>{title}</h3>
        <p>{desc}</p>
        <div className="modal-actions">
          <button className="btn" onClick={onCancel}>Cancel</button>
          <button className="btn" style={{ background: "#c0392b", color: "#fff", border: "none" }} onClick={onConfirm}>
            Delete
          </button>
        </div>
      </div>
    </div>
  );
}

// POST CARD 
function PostCard({ post, isRead, onClick, onTagClick, activeTag }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div
      className="card"
      onClick={() => onClick(post.id)}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{ cursor: "pointer", transform: hovered ? "translateY(-2px)" : "", boxShadow: hovered ? "0 4px 16px rgba(0,0,0,.1)" : "var(--shadow)", transition: "transform .15s, box-shadow .15s", overflow: "hidden" }}
    >
      {post.cover_image && (
        <div style={{ aspectRatio: "2.2/1", overflow: "hidden" }}>
          <img src={post.cover_image} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
        </div>
      )}
      <div style={{ padding: "16px 18px" }}>
        {post.tags?.length > 0 && (
          <div style={{ display: "flex", flexWrap: "wrap", gap: 5, marginBottom: 10 }}>
            {post.tags.slice(0, 4).map((t) => (
              <span
                key={t}
                className="tag-chip"
                style={activeTag === t ? { background: "var(--accent)", color: "#fff" } : {}}
                onClick={e => { e.stopPropagation(); onTagClick && onTagClick(t); }}
              >{t}</span>
            ))}
          </div>
        )}
        <h2 style={{ fontFamily: "Lora, serif", fontSize: 19, lineHeight: 1.35, marginBottom: 6 }}>{post.title}</h2>
        {post.subtitle && (
          <p style={{ color: "var(--muted)", fontSize: 13, lineHeight: 1.6, marginBottom: 12, display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden" }}>
            {post.subtitle}
          </p>
        )}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginTop: 10 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <div style={{ width: 26, height: 26, borderRadius: "50%", background: "var(--accent-light)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 600, color: "var(--accent)", flexShrink: 0 }}>
              {(post.author_name || "?")[0].toUpperCase()}
            </div>
            <div>
              <div style={{ fontSize: 12, fontWeight: 500 }}>{post.author_name}</div>
              <div style={{ fontSize: 11, color: "var(--muted)" }}>{timeAgo(post.created_date)}</div>
            </div>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 10, fontSize: 12, color: "var(--muted)" }}>
            {post.reading_time_minutes && (
              <span style={{ display: "flex", alignItems: "center", gap: 3 }}><Icon.clock />{post.reading_time_minutes}m</span>
            )}
            {isRead && (
              <span style={{ display: "flex", alignItems: "center", gap: 3, color: "var(--accent)" }}><Icon.eye />Read</span>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

//  HOME PAGE 
function HomePage({ nav, toast, initialTag }) {
  const [posts, setPosts] = useState([]);
  const [readIds, setReadIds] = useState(new Set());
  const [search, setSearch] = useState("");
  const [activeTag, setActiveTag] = useState(initialTag || null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    (async () => {
      setLoading(true);
      const published = await SharedDB.getPublished();
      const all = published.sort((a, b) => new Date(b.created_date) - new Date(a.created_date));
      setPosts(all);
      const hist = DB.getHistory();
      setReadIds(new Set(hist.map((h) => h.post_id)));
      setLoading(false);
    })();
  }, []);

  // Collect all tags with counts from published posts
  const tagCounts = posts.reduce((acc, p) => {
    (p.tags || []).forEach(t => { acc[t] = (acc[t] || 0) + 1; });
    return acc;
  }, {});
  // Sort tags: by count desc, then alpha
  const sortedTags = Object.entries(tagCounts)
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
    .map(([t]) => t);

  // Filter by search + active tag
  const filtered = posts.filter((p) => {
    const matchesSearch = !search || [p.title, p.subtitle, p.author_name, ...(p.tags || [])]
      .some(v => v?.toLowerCase().includes(search.toLowerCase()));
    const matchesTag = !activeTag || (p.tags || []).includes(activeTag);
    return matchesSearch && matchesTag;
  });

  function toggleTag(t) {
    setActiveTag(prev => prev === t ? null : t);
    setSearch("");
  }

  return (
    <div>
      {/* Hero */}
      <div style={{ textAlign: "center", marginBottom: 24 }}>
        <h1 style={{ fontSize: "clamp(22px,5vw,40px)", lineHeight: 1.2, marginBottom: 8 }}>
          Discover stories that matter
        </h1>
        <p style={{ color: "var(--muted)", fontSize: 15, maxWidth: 400, margin: "0 auto" }}>
          Read, write, and share ideas with a community of thoughtful minds.
        </p>
      </div>

      {/* Search bar */}
      <div style={{ maxWidth: 480, margin: "0 auto 16px", position: "relative" }}>
        <span style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "var(--muted)" }}>
          <Icon.search />
        </span>
        <input
          type="text"
          value={search}
          onChange={(e) => { setSearch(e.target.value); setActiveTag(null); }}
          placeholder="Search posts, authors, tags…"
          style={{ paddingLeft: 36, height: 42 }}
        />
      </div>

      {/* Tag filter bar — only show once posts are loaded and tags exist */}
      {!loading && sortedTags.length > 0 && (
        <div className="tag-bar" style={{ justifyContent: "center", marginBottom: 28 }}>
          {/* All / clear */}
          <button
            className={`tag-filter${!activeTag ? " active" : ""}`}
            onClick={() => { setActiveTag(null); setSearch(""); }}
          >
            All
            <span className="tag-count">{posts.length}</span>
          </button>
          {sortedTags.map(t => (
            <button
              key={t}
              className={`tag-filter${activeTag === t ? " active" : ""}`}
              onClick={() => toggleTag(t)}
            >
              {t}
              <span className="tag-count">{tagCounts[t]}</span>
            </button>
          ))}
        </div>
      )}

      {/* Active filter label */}
      {activeTag && (
        <div style={{ textAlign: "center", marginBottom: 16 }}>
          <span style={{ fontSize: 13, color: "var(--muted)" }}>
            Showing posts tagged{" "}
            <strong style={{ color: "var(--accent)" }}>"{activeTag}"</strong>
            {" · "}
            <button onClick={() => setActiveTag(null)}
              style={{ background: "none", border: "none", color: "var(--accent)", cursor: "pointer", fontSize: 13, textDecoration: "underline", padding: 0 }}>
              Clear
            </button>
          </span>
        </div>
      )}

      {loading ? (
        <div style={{ textAlign: "center", padding: "60px 20px" }}>
          <span className="spinner" style={{ margin: "0 auto" }} />
          <p style={{ color: "var(--muted)", marginTop: 16, fontSize: 14 }}>Loading the public feed…</p>
        </div>
      ) : filtered.length === 0 ? (
        <div className="empty">
          <p>
            {activeTag
              ? `No posts tagged "${activeTag}" yet.`
              : search
              ? "No posts match your search."
              : "No posts yet — be the first to write!"}
          </p>
          {activeTag && (
            <button className="btn" onClick={() => setActiveTag(null)} style={{ marginTop: 12 }}>
              View all posts
            </button>
          )}
        </div>
      ) : (
        <div className="post-grid">
          {filtered.map((p) => (
            <PostCard
              key={p.id}
              post={p}
              isRead={readIds.has(p.id)}
              onClick={(id) => nav("post", { id })}
              onTagClick={toggleTag}
              activeTag={activeTag}
            />
          ))}
        </div>
      )}
    </div>
  );
}

//  WRITE PAGE 
function WritePage({ nav, editId, toast }) {
  const user = DB.getUser();
  const [title, setTitle] = useState("");
  const [subtitle, setSubtitle] = useState("");
  const [content, setContent] = useState("");
  const [cover, setCover] = useState("");
  const [tagInput, setTagInput] = useState("");
  const [tags, setTags] = useState([]);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!editId) return;
    // Check drafts first, then published
    (async () => {
      let p = DB.getDrafts().find((x) => x.id === editId);
      if (!p) {
        const published = await SharedDB.getPublished();
        p = published.find((x) => x.id === editId);
      }
      if (!p) { toast("Post not found."); nav("my-posts"); return; }
      if (p.author_email !== user.email) { toast("You can only edit your own posts."); nav("my-posts"); return; }
      setTitle(p.title || "");
      setSubtitle(p.subtitle || "");
      setContent(p.content || "");
      setCover(p.cover_image || "");
      setTags(p.tags || []);
    })();
  }, [editId]);

  async function save(status) {
    if (!title.trim() || !content.trim()) {
      toast("Title and content are required.");
      return;
    }
    setSaving(true);

    const postData = {
      id: editId || uid(),
      title: title.trim(),
      subtitle: subtitle.trim(),
      content,
      cover_image: cover,
      tags,
      status,
      author_name: user.name,
      author_email: user.email,
      created_date: editId ? undefined : new Date().toISOString(),
      read_count: 0,
      reading_time_minutes: readTime(content),
    };

    if (status === "published") {
      // If was previously a draft, remove it from drafts
      if (editId) {
        const drafts = DB.getDrafts().filter(d => d.id !== editId);
        DB.saveDrafts(drafts);
        // Fetch existing published to preserve read_count / created_date
        const existing = (await SharedDB.getPublished()).find(p => p.id === editId);
        if (existing) {
          postData.read_count = existing.read_count || 0;
          postData.created_date = existing.created_date;
        }
      }
      if (!postData.created_date) postData.created_date = new Date().toISOString();
      await SharedDB.upsertPublished(postData);
    } else {
      // Draft — save locally; if it was previously published, remove from shared
      if (editId) {
        await SharedDB.deletePublished(editId);
      }
      const drafts = DB.getDrafts();
      const idx = drafts.findIndex(d => d.id === postData.id);
      if (!postData.created_date) postData.created_date = new Date().toISOString();
      if (idx > -1) drafts[idx] = postData; else drafts.unshift(postData);
      DB.saveDrafts(drafts);
    }

    setSaving(false);
    toast(status === "published" ? "Post published to the public feed!" : "Draft saved privately.");
    nav(status === "published" ? "home" : "my-posts");
  }

  function addTag() {
    if (tagInput.trim() && !tags.includes(tagInput.trim())) {
      setTags([...tags, tagInput.trim()]);
      setTagInput("");
    }
  }

  return (
    <div style={{ maxWidth: 680, margin: "0 auto", width: "100%" }}>
      <h1 className="page-header-h1" style={{ fontSize: 24, marginBottom: 20 }}>{editId ? "Edit Post" : "Write a Post"}</h1>

      <div className="field">
        <label>Title</label>
        <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Your compelling title…" style={{ fontSize: 17, fontFamily: "Lora, serif", height: 46 }} />
      </div>

      <div className="field">
        <label>Subtitle</label>
        <input type="text" value={subtitle} onChange={(e) => setSubtitle(e.target.value)} placeholder="A brief description…" />
      </div>

      <div className="field">
        <label>Header Image</label>
        <ImageUploader value={cover} onChange={setCover} />
      </div>

      <div className="field">
        <label>Tags</label>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
          {tags.map((t) => (
            <span key={t} style={{ display: "inline-flex", alignItems: "center", gap: 4 }} className="tag">
              {t}
              <button
                style={{ border: "none", background: "transparent", cursor: "pointer", lineHeight: 1, padding: "0 2px", color: "var(--muted)" }}
                onClick={() => setTags(tags.filter((x) => x !== t))}
              >
                <Icon.x />
              </button>
            </span>
          ))}
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          <input
            type="text"
            value={tagInput}
            onChange={(e) => setTagInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === "Enter") { e.preventDefault(); addTag(); } }}
            placeholder="Type a tag and press Enter…"
          />
          <button className="btn" onClick={addTag} style={{ whiteSpace: "nowrap" }}>Add</button>
        </div>
      </div>

      <div className="field">
        <label>Content <span style={{ fontWeight: 400, color: "var(--muted)", fontSize: 12 }}>— Markdown supported</span></label>
        <MarkdownEditor value={content} onChange={setContent} />
      </div>

      <div className="write-actions" style={{ paddingTop: 16, borderTop: "1px solid var(--border)" }}>
        <button className="btn btn-primary" onClick={() => save("published")} disabled={saving}>
          <Icon.send />{saving ? "Saving…" : "Publish"}
        </button>
        <button className="btn" onClick={() => save("draft")} disabled={saving}>
          <Icon.save />Save Draft
        </button>
        <button className="btn btn-ghost" onClick={() => nav("home")} style={{ marginLeft: "auto" }}>Cancel</button>
      </div>
    </div>
  );
}

//  POST DETAIL PAGE 
  const currentUser = DB.getUser();
  const [post, setPost] = useState(null);
  const [delConfirm, setDelConfirm] = useState(false);

  useEffect(() => {
    (async () => {
      // Try published (shared) first, then local drafts
      const published = await SharedDB.getPublished();
      let p = published.find((x) => x.id === id);
      let isPublished = !!p;
      if (!p) p = DB.getDrafts().find((x) => x.id === id);
      if (!p) { nav("home"); return; }
      setPost(p);

      // Track read for ALL published posts (including your own)
      if (isPublished) {
        const hist = DB.getHistory();
        const alreadyRead = hist.find((h) => h.post_id === id && h.reader_email === currentUser.email);
        if (!alreadyRead) {
          hist.unshift({
            id: uid(),
            post_id: id,
            post_title: p.title,
            post_subtitle: p.subtitle || "",
            post_cover: p.cover_image || "",
            post_author: p.author_name || "",
            post_tags: p.tags || [],
            post_reading_time: p.reading_time_minutes || 1,
            reader_email: currentUser.email,
            read_at: new Date().toISOString(),
          });
          DB.saveHistory(hist);
          // Increment read_count for posts read by others
          if (p.author_email !== currentUser.email) {
            const updated = { ...p, read_count: (p.read_count || 0) + 1 };
            await SharedDB.upsertPublished(updated);
            setPost(updated);
          }
        }
      }
    })();
  }, [id]);

  async function handleDelete() {
    const post = (await SharedDB.getPublished()).find(p => p.id === id);
    if (post) {
      await SharedDB.deletePublished(id);
    } else {
      DB.saveDrafts(DB.getDrafts().filter(p => p.id !== id));
    }
    toast("Post deleted.");
    nav("my-posts");
  }

  if (!post) return <span className="spinner" />;

  const isAuthor = post.author_email === currentUser.email;

  return (
    <div style={{ maxWidth: 680, margin: "0 auto", width: "100%" }}>
      {delConfirm && (
        <Confirm
          title="Delete this post?"
          desc={`"${post.title}" will be permanently deleted.`}
          onConfirm={handleDelete}
          onCancel={() => setDelConfirm(false)}
        />
      )}

      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 16, gap: 8 }}>
        <button className="btn btn-ghost" style={{ padding: "7px 10px" }} onClick={() => nav("home")}><Icon.back /><span className="post-row-label">Back</span></button>
        {isAuthor && (
          <div style={{ display: "flex", gap: 6 }}>
            <button className="btn" onClick={() => nav("write", { editId: post.id })} style={{ fontSize: 13, padding: "7px 10px" }}>
              <Icon.edit /><span className="post-row-label">Edit</span>
            </button>
            <button className="btn btn-danger" onClick={() => setDelConfirm(true)} style={{ fontSize: 13, padding: "7px 10px" }}>
              <Icon.trash /><span className="post-row-label">Delete</span>
            </button>
          </div>
        )}
      </div>

      {post.cover_image && (
        <img src={post.cover_image} alt="" style={{ width: "100%", maxHeight: 360, objectFit: "cover", borderRadius: 12, marginBottom: 24, display: "block" }} />
      )}

      {post.tags?.length > 0 && (
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 16 }}>
          {post.tags.map((t) => (
            <span
              key={t}
              className="tag-chip"
              onClick={() => nav("home", { tag: t })}
              title={`Browse posts tagged "${t}"`}
            >{t}</span>
          ))}
        </div>
      )}

      <h1 className="post-detail-title" style={{ fontSize: "clamp(20px,4vw,34px)", lineHeight: 1.25, marginBottom: 12 }}>{post.title}</h1>
      {post.subtitle && <p style={{ color: "var(--muted)", fontSize: 16, marginBottom: 20, lineHeight: 1.6 }}>{post.subtitle}</p>}

      <div style={{ display: "flex", alignItems: "center", gap: 14, paddingBottom: 24, borderBottom: "1px solid var(--border)", marginBottom: 32 }}>
        <div style={{ width: 40, height: 40, borderRadius: "50%", background: "var(--accent-light)", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 600, color: "var(--accent)", fontSize: 15 }}>
          {(post.author_name || "?")[0].toUpperCase()}
        </div>
        <div>
          <div style={{ fontWeight: 500, fontSize: 14 }}>{post.author_name}{isAuthor && <span style={{ marginLeft: 8, fontSize: 11, background: "var(--accent-light)", color: "var(--accent)", padding: "2px 8px", borderRadius: 20, fontWeight: 500 }}>You</span>}</div>
          <div style={{ display: "flex", gap: 12, fontSize: 12, color: "var(--muted)", marginTop: 2 }}>
            <span style={{ display: "flex", alignItems: "center", gap: 3 }}>
              <Icon.cal />{new Date(post.created_date).toLocaleDateString("en", { month: "short", day: "numeric", year: "numeric" })}
            </span>
            {post.reading_time_minutes && (
              <span style={{ display: "flex", alignItems: "center", gap: 3 }}><Icon.clock />{post.reading_time_minutes} min read</span>
            )}
            <span style={{ display: "flex", alignItems: "center", gap: 3 }}><Icon.eye />{post.read_count || 0} reads</span>
          </div>
        </div>
      </div>

      <div className="post-content md-preview" dangerouslySetInnerHTML={{ __html: parseMarkdown(post.content || "") }} />
    </div>
  );


// MY POSTS PAGE 
function MyPostsPage({ nav, toast }) {
  const user = DB.getUser();
  const [posts, setPosts] = useState([]);
  const [delTarget, setDelTarget] = useState(null);
  const [loading, setLoading] = useState(true);

  async function loadPosts() {
    setLoading(true);
    const myDrafts = DB.getDrafts().filter(p => p.author_email === user.email);
    const allPublished = await SharedDB.getPublished();
    const myPublished = allPublished.filter(p => p.author_email === user.email);
    const all = [...myPublished, ...myDrafts].sort((a, b) => new Date(b.created_date) - new Date(a.created_date));
    setPosts(all);
    setLoading(false);
  }

  useEffect(() => { loadPosts(); }, []);

  async function doDelete(id) {
    const post = posts.find(p => p.id === id);
    if (!post) { toast("Post not found."); setDelTarget(null); return; }
    if (post.author_email !== user.email) { toast("You can only delete your own posts."); setDelTarget(null); return; }
    if (post.status === "published") {
      await SharedDB.deletePublished(id);
    } else {
      DB.saveDrafts(DB.getDrafts().filter(p => p.id !== id));
    }
    setPosts(posts.filter(p => p.id !== id));
    setDelTarget(null);
    toast("Post deleted.");
  }

  return (
    <div>
      {delTarget && (
        <Confirm
          title="Delete this post?"
          desc={`"${delTarget.title}" will be permanently deleted.`}
          onConfirm={() => doDelete(delTarget.id)}
          onCancel={() => setDelTarget(null)}
        />
      )}

      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 24, gap: 12 }}>
        <div>
          <h1 className="page-header-h1" style={{ fontSize: 24 }}>My Posts</h1>
          <p style={{ color: "var(--muted)", fontSize: 13, marginTop: 4 }}>{posts.length} post{posts.length !== 1 ? "s" : ""}</p>
        </div>
        <button className="btn btn-primary" style={{ flexShrink: 0 }} onClick={() => nav("write")}><Icon.pen /><span className="post-row-label">New Post</span></button>
      </div>

      {loading ? (
        <div style={{ textAlign: "center", padding: 40 }}><span className="spinner" style={{ margin: "0 auto" }} /></div>
      ) : posts.length === 0 ? (
        <div className="empty card" style={{ padding: 60 }}>
          <p style={{ marginBottom: 16 }}>You haven't written any posts yet.</p>
          <button className="btn btn-primary" onClick={() => nav("write")}>Start Writing</button>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {posts.map((p) => (
            <div key={p.id} className="card" style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 16px" }}>
              <div className="post-row-thumb">
                {p.cover_image ? (
                  <img src={p.cover_image} alt="" style={{ width: 64, height: 48, objectFit: "cover", borderRadius: 6, display: "block" }} />
                ) : (
                  <div style={{ width: 64, height: 48, background: "var(--bg)", borderRadius: 6, display: "flex", alignItems: "center", justifyContent: "center", color: "var(--muted)" }}>
                    <Icon.lib />
                  </div>
                )}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                  <span style={{ fontWeight: 600, fontSize: 14, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{p.title}</span>
                  <span className={`badge badge-${p.status}`}>{p.status}</span>
                </div>
                <div style={{ fontSize: 12, color: "var(--muted)", display: "flex", gap: 10 }}>
                  <span>{new Date(p.created_date).toLocaleDateString("en", { month: "short", day: "numeric", year: "numeric" })}</span>
                  <span style={{ display: "flex", alignItems: "center", gap: 3 }}><Icon.eye />{p.read_count || 0}</span>
                </div>
              </div>
              <div style={{ display: "flex", gap: 4, flexShrink: 0 }}>
                <button className="btn btn-ghost" style={{ padding: "6px 8px" }} onClick={() => nav("write", { editId: p.id })}><Icon.edit /></button>
                {p.status === "published" && (
                  <button className="btn btn-ghost" style={{ padding: "6px 8px" }} onClick={() => nav("post", { id: p.id })}><Icon.eye /></button>
                )}
                <button className="btn btn-danger" style={{ padding: "6px 8px" }} onClick={() => setDelTarget(p)}><Icon.trash /></button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// READING HISTORY PAGE 
function ReadingHistoryPage({ nav }) {
  const user = DB.getUser();
  const [history, setHistory] = useState([]);
  const [search, setSearch] = useState("");

  useEffect(() => {
    setHistory(
      DB.getHistory()
        .filter((h) => h.reader_email === user.email)
        .sort((a, b) => new Date(b.read_at) - new Date(a.read_at))
    );
  }, []);

  const filtered = history.filter((h) =>
    [h.post_title, h.post_author, ...(h.post_tags || [])].some((v) =>
      v?.toLowerCase().includes(search.toLowerCase())
    )
  );

  // Group by date label
  function dateLabel(iso) {
    const d = new Date(iso);
    const now = new Date();
    const diffDays = Math.floor((now - d) / 86400000);
    if (diffDays === 0) return "Today";
    if (diffDays === 1) return "Yesterday";
    if (diffDays < 7) return d.toLocaleDateString("en", { weekday: "long" });
    if (diffDays < 365) return d.toLocaleDateString("en", { month: "long", day: "numeric" });
    return d.toLocaleDateString("en", { month: "long", day: "numeric", year: "numeric" });
  }

  // Build grouped list
  const groups = [];
  let lastLabel = null;
  for (const h of filtered) {
    const label = dateLabel(h.read_at || h.created_date);
    if (label !== lastLabel) { groups.push({ label, items: [] }); lastLabel = label; }
    groups[groups.length - 1].items.push(h);
  }

  return (
    <div style={{ maxWidth: 720, margin: "0 auto" }}>
      {/* Header */}
      <div className="hist-header" style={{ display: "flex", alignItems: "flex-end", justifyContent: "space-between", marginBottom: 24, flexWrap: "wrap", gap: 12 }}>
        <div>
          <h1 className="page-header-h1" style={{ fontSize: 24, marginBottom: 4 }}>Reading History</h1>
          <p style={{ color: "var(--muted)", fontSize: 13 }}>
            {history.length} post{history.length !== 1 ? "s" : ""} read
          </p>
        </div>
        {history.length > 0 && (
          <div className="hist-search" style={{ position: "relative" }}>
            <span style={{ position: "absolute", left: 10, top: "50%", transform: "translateY(-50%)", color: "var(--muted)" }}><Icon.search /></span>
            <input type="text" value={search} onChange={e => setSearch(e.target.value)}
              placeholder="Search history…"
              style={{ paddingLeft: 32, height: 36, width: 200, fontSize: 13 }} />
          </div>
        )}
      </div>

      {history.length === 0 ? (
        <div className="empty card" style={{ padding: 60 }}>
          <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.2" style={{ margin: "0 auto 12px", display: "block", opacity: .3 }}>
            <path d="M2 3h6a4 4 0 014 4v14a3 3 0 00-3-3H2z"/><path d="M22 3h-6a4 4 0 00-4 4v14a3 3 0 013-3h7z"/>
          </svg>
          <p style={{ marginBottom: 16, color: "var(--muted)" }}>You haven't read any posts yet.</p>
          <button className="btn btn-primary" onClick={() => nav("home")}>Browse the Feed</button>
        </div>
      ) : filtered.length === 0 ? (
        <div className="empty"><p>No posts match "{search}".</p></div>
      ) : (
        <div>
          {groups.map((group) => (
            <div key={group.label} style={{ marginBottom: 28 }}>
              {/* Date group label */}
              <div style={{ fontSize: 11, fontWeight: 600, color: "var(--muted)", textTransform: "uppercase", letterSpacing: ".08em", marginBottom: 10, paddingLeft: 2 }}>
                {group.label}
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {group.items.map((h) => (
                  <div
                    key={h.id}
                    className="card"
                    onClick={() => nav("post", { id: h.post_id })}
                    style={{ display: "flex", alignItems: "center", gap: 14, padding: "12px 14px", cursor: "pointer", transition: "box-shadow .15s, transform .15s" }}
                    onMouseEnter={(e) => { e.currentTarget.style.boxShadow = "0 4px 14px rgba(0,0,0,.09)"; e.currentTarget.style.transform = "translateY(-1px)"; }}
                    onMouseLeave={(e) => { e.currentTarget.style.boxShadow = "var(--shadow)"; e.currentTarget.style.transform = ""; }}
                  >
                    {/* Thumbnail or fallback */}
                    <div className="hist-thumb" style={{ flexShrink: 0 }}>
                      {h.post_cover ? (
                        <img src={h.post_cover} alt="" style={{ width: 64, height: 48, objectFit: "cover", borderRadius: 6, display: "block" }} />
                      ) : (
                        <div style={{ width: 64, height: 48, borderRadius: 6, background: "var(--accent-light)", display: "flex", alignItems: "center", justifyContent: "center", color: "var(--accent)" }}>
                          <Icon.book />
                        </div>
                      )}
                    </div>

                    {/* Post info */}
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontWeight: 600, fontSize: 14, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", marginBottom: 3 }}>
                        {h.post_title}
                      </div>
                      <div style={{ display: "flex", alignItems: "center", gap: 10, fontSize: 12, color: "var(--muted)", flexWrap: "wrap" }}>
                        {h.post_author && <span>{h.post_author}</span>}
                        {h.post_reading_time && (
                          <span style={{ display: "flex", alignItems: "center", gap: 3 }}>
                            <Icon.clock />{h.post_reading_time} min
                          </span>
                        )}
                        {h.post_tags?.length > 0 && (
                          <span style={{ display: "flex", gap: 4 }}>
                            {h.post_tags.slice(0, 2).map(t => (
                              <span key={t} className="tag" style={{ fontSize: 10, padding: "2px 7px" }}>{t}</span>
                            ))}
                          </span>
                        )}
                      </div>
                    </div>

                    {/* Time ago */}
                    <div style={{ fontSize: 11, color: "var(--muted)", flexShrink: 0, textAlign: "right" }}>
                      {timeAgo(h.read_at || h.created_date)}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}


//  AUTH PAGES 
function AuthPage({ onAuth, toast }) {
  const [mode, setMode] = useState("login"); // "login" | "register"
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [pw, setPw] = useState("");
  const [confirmPw, setConfirmPw] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPw, setShowPw] = useState(false);

  function submit() {
    const emailTrim = email.trim().toLowerCase();
    const nameTrim = name.trim();
    if (!emailTrim || !pw) { toast("Email and password are required."); return; }
    if (!/^[^@]+@[^@]+\.[^@]+$/.test(emailTrim)) { toast("Enter a valid email address."); return; }
    if (pw.length < 6) { toast("Password must be at least 6 characters."); return; }

    setLoading(true);
    const users = DB.getUsers();

    if (mode === "register") {
      if (!nameTrim) { toast("Name is required."); setLoading(false); return; }
      if (pw !== confirmPw) { toast("Passwords do not match."); setLoading(false); return; }
      if (users.find(u => u.email === emailTrim)) { toast("An account with that email already exists."); setLoading(false); return; }
      const user = { id: uid(), name: nameTrim, email: emailTrim, hash: hashPassword(pw), createdAt: new Date().toISOString() };
      users.push(user);
      DB.saveUsers(users);
      const session = { id: user.id, name: user.name, email: user.email };
      DB.saveSession(session);
      toast("Account created! Welcome to YouWrite.");
      onAuth(session);
    } else {
      const user = users.find(u => u.email === emailTrim);
      if (!user || user.hash !== hashPassword(pw)) { toast("Invalid email or password."); setLoading(false); return; }
      const session = { id: user.id, name: user.name, email: user.email };
      DB.saveSession(session);
      toast("Welcome back, " + user.name + "!");
      onAuth(session);
    }
    setLoading(false);
  }

  const eyeIcon = (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      {showPw
        ? <><path d="M17.94 17.94A10.07 10.07 0 0112 20c-7 0-11-8-11-8a18.45 18.45 0 015.06-5.94"/><path d="M9.9 4.24A9.12 9.12 0 0112 4c7 0 11 8 11 8a18.5 18.5 0 01-2.16 3.19"/><line x1="1" y1="1" x2="23" y2="23"/></>
        : <><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></>}
    </svg>
  );

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", background: "var(--bg)", padding: "24px 16px" }}>
      {/* Logo */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 40 }}>
        <img src={LOGO_B64} alt="YouWrite" style={{ width: 40, height: 40, borderRadius: 10, objectFit: "cover" }} />
        <span style={{ fontFamily: "Lora, serif", fontWeight: 700, fontSize: 22, color: "var(--text)" }}>YouWrite</span>
      </div>

      {/* Card */}
      <div className="card auth-card-pad" style={{ width: "100%", maxWidth: 420 }}>
        <h1 style={{ fontFamily: "Lora, serif", fontSize: 22, marginBottom: 6, textAlign: "center" }}>
          {mode === "login" ? "Welcome back" : "Create your account"}
        </h1>
        <p style={{ color: "var(--muted)", fontSize: 14, textAlign: "center", marginBottom: 28 }}>
          {mode === "login" ? "Sign in to continue writing." : "Join and start sharing your stories."}
        </p>

        {mode === "register" && (
          <div className="field">
            <label>Full Name</label>
            <input type="text" value={name} onChange={e => setName(e.target.value)} placeholder="Jane Smith" onKeyDown={e => e.key === "Enter" && submit()} />
          </div>
        )}

        <div className="field">
          <label>Email</label>
          <input type="text" value={email} onChange={e => setEmail(e.target.value)} placeholder="you@example.com" onKeyDown={e => e.key === "Enter" && submit()} />
        </div>

        <div className="field">
          <label>Password</label>
          <div style={{ position: "relative" }}>
            <input
              type={showPw ? "text" : "password"}
              value={pw}
              onChange={e => setPw(e.target.value)}
              placeholder={mode === "register" ? "At least 6 characters" : "••••••••"}
              onKeyDown={e => e.key === "Enter" && submit()}
              style={{ paddingRight: 40 }}
            />
            <button
              onClick={() => setShowPw(v => !v)}
              style={{ position: "absolute", right: 10, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", color: "var(--muted)", display: "flex", alignItems: "center" }}
            >{eyeIcon}</button>
          </div>
        </div>

        {mode === "register" && (
          <div className="field">
            <label>Confirm Password</label>
            <input
              type={showPw ? "text" : "password"}
              value={confirmPw}
              onChange={e => setConfirmPw(e.target.value)}
              placeholder="Re-enter your password"
              onKeyDown={e => e.key === "Enter" && submit()}
            />
          </div>
        )}

        {mode === "login" && (
          <div style={{ textAlign: "right", marginTop: -10, marginBottom: 18 }}>
            <span style={{ fontSize: 13, color: "var(--muted)" }}>Forgot password? <span style={{ color: "var(--accent)", cursor: "pointer" }} onClick={() => toast("Password reset isn't available in this demo.")}>Reset</span></span>
          </div>
        )}

        <button
          className="btn btn-primary"
          onClick={submit}
          disabled={loading}
          style={{ width: "100%", justifyContent: "center", height: 44, fontSize: 15, marginBottom: 16 }}
        >
          {loading ? "Please wait…" : mode === "login" ? "Sign In" : "Create Account"}
        </button>

        <div style={{ textAlign: "center", fontSize: 14, color: "var(--muted)" }}>
          {mode === "login" ? (
            <>Don't have an account?{" "}<span style={{ color: "var(--accent)", cursor: "pointer", fontWeight: 500 }} onClick={() => { setMode("register"); setPw(""); setConfirmPw(""); }}>Sign Up</span></>
          ) : (
            <>Already have an account?{" "}<span style={{ color: "var(--accent)", cursor: "pointer", fontWeight: 500 }} onClick={() => { setMode("login"); setPw(""); setConfirmPw(""); }}>Sign In</span></>
          )}
        </div>
      </div>

      <p style={{ fontSize: 12, color: "var(--muted)", marginTop: 24, textAlign: "center", maxWidth: 340 }}>
        All data is stored locally in your browser. No server involved.
      </p>
    </div>
  );
}

// NAV DEFINITION 
const NAV_ITEMS = [
  { id: "home", label: "Feed", icon: "home" },
  { id: "write", label: "Write", icon: "pen" },
  { id: "my-posts", label: "My Posts", icon: "lib" },
  { id: "reading-history", label: "Read", icon: "book" },
];
const ICON_MAP = { home: Icon.home, pen: Icon.pen, lib: Icon.lib, book: Icon.book };

// APP ROOT 
export default function App() {
  const [session, setSession] = useState(() => DB.getSession());
  const [page, setPage] = useState({ name: "home", params: {} });
  const [toastMsg, setToastMsg] = useState(null);
  const [userMenuOpen, setUserMenuOpen] = useState(false);

  function nav(name, params = {}) {
    setPage({ name, params });
    setUserMenuOpen(false);
    window.scrollTo(0, 0);
  }

  function toast(msg) { setToastMsg(msg); }

  function handleAuth(sess) { setSession(sess); }

  function logout() {
    DB.clearSession();
    setSession(null);
    setUserMenuOpen(false);
    setPage({ name: "home", params: {} });
    toast("Signed out successfully.");
  }

  // Close user menu on outside click
  useEffect(() => {
    if (!userMenuOpen) return;
    const handler = () => setUserMenuOpen(false);
    setTimeout(() => document.addEventListener("click", handler), 0);
    return () => document.removeEventListener("click", handler);
  }, [userMenuOpen]);

  if (!session) {
    return (
      <div style={{ minHeight: "100vh", width: "100%", background: "var(--bg)" }}>
        <GlobalStyles />
        {toastMsg && <Toast msg={toastMsg} onDone={() => setToastMsg(null)} />}
        <AuthPage onAuth={handleAuth} toast={toast} />
      </div>
    );
  }

  const initials = (session.name || "?").split(" ").map(w => w[0]).join("").toUpperCase().slice(0, 2);

  return (
    <div style={{ minHeight: "100vh", width: "100%", background: "var(--bg)" }}>
      <GlobalStyles />
      {toastMsg && <Toast msg={toastMsg} onDone={() => setToastMsg(null)} />}

      {/* ── DESKTOP HEADER ── */}
      <header style={{ position: "sticky", top: 0, zIndex: 100, background: "rgba(28,27,24,.92)", backdropFilter: "blur(12px)", borderBottom: "1px solid var(--border)" }}>
        <div style={{ maxWidth: 1000, margin: "0 auto", padding: "0 16px", height: 56, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          {/* Logo */}
          <button onClick={() => nav("home")} style={{ display: "flex", alignItems: "center", gap: 8, background: "none", border: "none", cursor: "pointer", flexShrink: 0 }}>
            <img src={LOGO_B64} alt="YouWrite logo" style={{ width: 32, height: 32, borderRadius: 7, objectFit: "cover" }} />
            <span style={{ fontFamily: "Lora, serif", fontWeight: 600, fontSize: 18 }}>YouWrite</span>
          </button>

          {/* Desktop nav — hidden on mobile */}
          <div className="hide-mobile" style={{ alignItems: "center", gap: 4 }}>
            <nav style={{ display: "flex", gap: 2 }}>
              {NAV_ITEMS.map(({ id, label, icon }) => {
                const Ic = ICON_MAP[icon];
                return (
                  <button key={id} onClick={() => nav(id)} className="btn btn-ghost"
                    style={{ color: page.name === id ? "var(--accent)" : "var(--muted)", background: page.name === id ? "var(--accent-light)" : "transparent", borderColor: "transparent", padding: "7px 12px" }}>
                    <Ic />{label}
                  </button>
                );
              })}
            </nav>

            {/* Avatar + dropdown */}
            <div style={{ position: "relative", marginLeft: 8 }}>
              <button onClick={e => { e.stopPropagation(); setUserMenuOpen(v => !v); }}
                style={{ width: 34, height: 34, borderRadius: "50%", background: "var(--accent)", color: "#fff", border: "none", cursor: "pointer", fontWeight: 600, fontSize: 12, display: "flex", alignItems: "center", justifyContent: "center" }}
                title={session.name}>
                {initials}
              </button>
              {userMenuOpen && (
                <div onClick={e => e.stopPropagation()} style={{ position: "absolute", right: 0, top: "calc(100% + 8px)", background: "var(--surface)", border: "1px solid var(--border)", borderRadius: 10, padding: "6px 0", minWidth: 200, boxShadow: "0 4px 20px rgba(0,0,0,.1)", zIndex: 200 }}>
                  <div style={{ padding: "10px 16px", borderBottom: "1px solid var(--border)", marginBottom: 4 }}>
                    <div style={{ fontWeight: 600, fontSize: 14 }}>{session.name}</div>
                    <div style={{ fontSize: 12, color: "var(--muted)", marginTop: 2 }}>{session.email}</div>
                  </div>
                  {[{ label: "My Posts", id: "my-posts" }, { label: "Reading History", id: "reading-history" }].map(item => (
                    <button key={item.id} className="btn btn-ghost" onClick={() => nav(item.id)}
                      style={{ display: "block", width: "100%", textAlign: "left", borderRadius: 0, padding: "8px 16px", border: "none", fontSize: 14 }}>
                      {item.label}
                    </button>
                  ))}
                  <div style={{ borderTop: "1px solid var(--border)", marginTop: 4, paddingTop: 4 }}>
                    <button className="btn btn-ghost" onClick={logout}
                      style={{ display: "block", width: "100%", textAlign: "left", borderRadius: 0, padding: "8px 16px", border: "none", fontSize: 14, color: "var(--danger)" }}>
                      Sign Out
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Mobile: avatar only (nav is bottom bar) */}
          <div className="show-mobile" style={{ alignItems: "center", gap: 8 }}>
            <button onClick={e => { e.stopPropagation(); setUserMenuOpen(v => !v); }}
              style={{ width: 34, height: 34, borderRadius: "50%", background: "var(--accent)", color: "#fff", border: "none", cursor: "pointer", fontWeight: 600, fontSize: 12, display: "flex", alignItems: "center", justifyContent: "center" }}>
              {initials}
            </button>
            {userMenuOpen && (
              <div onClick={e => e.stopPropagation()} style={{ position: "fixed", top: 52, right: 12, background: "var(--surface)", border: "1px solid var(--border)", borderRadius: 10, padding: "6px 0", minWidth: 200, boxShadow: "0 4px 20px rgba(0,0,0,.15)", zIndex: 200 }}>
                <div style={{ padding: "10px 16px", borderBottom: "1px solid var(--border)", marginBottom: 4 }}>
                  <div style={{ fontWeight: 600, fontSize: 14 }}>{session.name}</div>
                  <div style={{ fontSize: 12, color: "var(--muted)", marginTop: 2 }}>{session.email}</div>
                </div>
                <div style={{ borderTop: "1px solid var(--border)", marginTop: 4, paddingTop: 4 }}>
                  <button className="btn btn-ghost" onClick={logout}
                    style={{ display: "block", width: "100%", textAlign: "left", borderRadius: 0, padding: "8px 16px", border: "none", fontSize: 14, color: "var(--danger)" }}>
                    Sign Out
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </header>

      {/*  MAIN */}
      <main style={{ maxWidth: 1000, margin: "0 auto", width: "100%", padding: "28px 16px 36px" }}>
        {page.name === "home"            && <HomePage nav={nav} toast={toast} initialTag={page.params.tag || null} />}
        {page.name === "write"           && <WritePage nav={nav} editId={page.params.editId} toast={toast} />}
        {page.name === "post"            && <PostDetailPage id={page.params.id} nav={nav} toast={toast} />}
        {page.name === "my-posts"        && <MyPostsPage nav={nav} toast={toast} />}
        {page.name === "reading-history" && <ReadingHistoryPage nav={nav} />}
      </main>

      {/* MOBILE BOTTOM NAV  */}
      <nav className="bottom-nav">
        {NAV_ITEMS.map(({ id, label, icon }) => {
          const Ic = ICON_MAP[icon];
          return (
            <button key={id} className={`bottom-nav-item${page.name === id ? " active" : ""}`} onClick={() => nav(id)}>
              <Ic />
              <span>{label}</span>
            </button>
          );
        })}
        <button className="bottom-nav-item" onClick={e => { e.stopPropagation(); setUserMenuOpen(v => !v); }}>
          <div style={{ width: 20, height: 20, borderRadius: "50%", background: "var(--accent)", color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9, fontWeight: 700 }}>{initials}</div>
          <span>Account</span>
        </button>
      </nav>
    </div>
  );
}